<?= $this->include('template/admin_header') ?><h2><?= $title ?></h2><form method="get" class="form-search"><input type="text" name="q" value="<?= esc($q) ?>" placeholder="Cari judul artikel"><select name="kategori_id"><option value="">Semua Kategori</option><?php foreach($kategori as $k): ?><option value="<?= $k['id_kategori'] ?>" <?= ($kategori_id==$k['id_kategori'])?'selected':'' ?>><?= esc($k['nama_kategori']) ?></option><?php endforeach; ?></select><button type="submit">Cari</button></form><p><a class="btn btn-primary" href="<?= base_url('/admin/artikel/add') ?>">+ Tambah Artikel</a></p><div id="article-container"><table class="table"><thead><tr><th>ID</th><th>Judul</th><th>Kategori</th><th>Status</th><th>Gambar</th><th>Aksi</th></tr></thead><tbody><?php foreach($artikel as $row): ?><tr><td><?= $row['id'] ?></td><td><b><?= esc($row['judul']) ?></b><br><small><?= esc(substr(strip_tags($row['isi']),0,60)) ?></small></td><td><?= esc($row['nama_kategori'] ?? '-') ?></td><td><?= $row['status'] ? 'Publish' : 'Draft' ?></td><td><?php if($row['gambar']): ?><img src="<?= base_url('/gambar/'.$row['gambar']) ?>" width="60"><?php endif; ?></td><td><a class="btn" href="<?= base_url('/admin/artikel/edit/'.$row['id']) ?>">Ubah</a> <a class="btn btn-danger" onclick="return confirm('Yakin hapus data?')" href="<?= base_url('/admin/artikel/delete/'.$row['id']) ?>">Hapus</a></td></tr><?php endforeach; ?></tbody></table></div><div id="pagination-container"><?= $pager->links() ?></div><script src="https://code.jquery.com/jquery-3.6.0.min.js"></script><script>$('.form-search').on('submit',function(e){e.preventDefault();$.ajax({url:'<?= base_url('/admin/artikel') ?>',data:$(this).serialize(),headers:{'X-Requested-With':'XMLHttpRequest'},success:function(data){let html='<table class="table"><thead><tr><th>ID</th><th>Judul</th><th>Kategori</th><th>Status</th><th>Aksi</th></tr></thead><tbody>';data.artikel.forEach(function(a){html+=`<tr><td>${a.id}</td><td><b>${a.judul}</b><br><small>${(a.isi||'').substring(0,60)}</small></td><td>${a.nama_kategori||'-'}</td><td>${a.status==1?'Publish':'Draft'}</td><td><a href='<?= base_url('/admin/artikel/edit/') ?>${a.id}'>Ubah</a> <a href='<?= base_url('/admin/artikel/delete/') ?>${a.id}' onclick="return confirm('Yakin hapus?')">Hapus</a></td></tr>`});html+='</tbody></table>';$('#article-container').html(html);}})});</script><?= $this->include('template/admin_footer') ?>
